insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q001', (select id from chapters where code='sci-chem'), 201, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What are the basic building blocks of chalk called?', null, '["Constituent particles", "Atoms", "Molecules", "Grains"]'::jsonb, 0, 'Constituent particles', 'Constituent particles are the smallest units that make up chalk.  ▸ Textbook: These units are called constituent particles of chalk.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q002', (select id from chapters where code='sci-chem'), 201, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What happens to sugar when it dissolves in water?', null, '["It changes into a new substance", "It breaks into its constituent particles", "It remains unchanged", "It evaporates"]'::jsonb, 1, 'It breaks into its constituent particles', 'Sugar breaks into smaller particles that mix with water.  ▸ Textbook: When sugar dissolves in water, it breaks up into its constituent particles which cannot be broken down further.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q003', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Why do solids have a definite shape?', null, '["Because their particles are loosely packed", "Because their particles are tightly packed", "Because they have no interparticle forces", "Because they are made of large particles"]'::jsonb, 1, 'Because their particles are tightly packed', 'Strong forces keep solid particles in fixed positions.  ▸ Textbook: In solids, the particles are tightly packed and the interparticle attractions are very strong.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q005', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'How do liquids differ from solids in terms of shape?', null, '["Liquids have a fixed shape", "Liquids take the shape of their container", "Liquids have a definite shape", "Liquids cannot change shape"]'::jsonb, 1, 'Liquids take the shape of their container', 'Liquids flow and adapt to the shape of their container.  ▸ Textbook: Liquids do not have a fixed shape and take the shape of the container they are kept in.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q006', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What happens to the interparticle forces when a solid is heated?', null, '["They become stronger", "They remain unchanged", "They get weakened", "They disappear completely"]'::jsonb, 2, 'They get weakened', 'Heating makes particles vibrate more, weakening the forces.  ▸ Textbook: The interparticle forces of attraction get weakened and the solid gets converted into the liquid state.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q007', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following states of matter has the weakest interparticle attractions?', null, '["Solid", "Liquid", "Gas", "Plasma"]'::jsonb, 2, 'Gas', 'Gas particles move freely with very little attraction between them.  ▸ Textbook: In gases, the interparticle attractions are negligible.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q008', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the boiling point of water?', null, '["0 °C", "100 °C", "133 °C", "1538 °C"]'::jsonb, 1, '100 °C', 'Water boils at 100 degrees Celsius.  ▸ Textbook: Recall Curiosity, Grade 6 chapter ‘Temperature and Its Measurement’, where you observed the temperature of boiling water (liquid).');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q009', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'How do gases behave in a container?', null, '["They have a fixed volume", "They fill the entire available space", "They stay at the bottom", "They form layers"]'::jsonb, 1, 'They fill the entire available space', 'Gases spread out to fill any container they are in.  ▸ Textbook: The smoke fills the entire space in the Gas Jar B, indicating that gases do not have a fixed volume and tend to occupy the entire available space.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q010', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What happens to the particles of a liquid when it is heated to its boiling point?', null, '["They move closer together", "They stop moving", "They move apart and form a gas", "They become solid"]'::jsonb, 2, 'They move apart and form a gas', 'Heating causes particles to move faster and spread out into a gas.  ▸ Textbook: The movement of particles becomes so vigorous that they move apart from each other, resulting in a decrease in the interparticle forces of attraction.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q011', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the process called when a liquid turns into a gas at temperatures below its boiling point?', null, '["Condensation", "Evaporation", "Sublimation", "Freezing"]'::jsonb, 1, 'Evaporation', 'Evaporation is when a liquid slowly turns into gas at lower temperatures.  ▸ Textbook: This slower process is known as evaporation — about which you have learnt in earlier grades.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q012', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Which of the following is true about the particles in a solid?', null, '["They can move freely past each other", "They are in fixed positions and can only vibrate", "They are far apart from each other", "They have no interparticle attractions"]'::jsonb, 1, 'They are in fixed positions and can only vibrate', 'Solid particles are tightly packed and can only vibrate in place.  ▸ Textbook: The particles can only move to and fro about their positions (vibrate or oscillate) but cannot move past each other.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q013', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What determines the physical state of a substance?', null, '["The size of its particles", "The color of the substance", "The strength of interparticle attractions", "The temperature of the environment"]'::jsonb, 2, 'The strength of interparticle attractions', 'The stronger the attractions, the more solid the state.  ▸ Textbook: The strength of these forces ultimately decides the physical state of the substances.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q014', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Why do gases not have a fixed shape or volume?', null, '["Because their particles are tightly packed", "Because their particles are loosely packed", "Because their particles are free to move in all directions", "Because they are made of large particles"]'::jsonb, 2, 'Because their particles are free to move in all directions', 'Gas particles move freely, so they spread out and fill any space.  ▸ Textbook: The particles in gases move freely in all directions and the interparticle attractions are negligible.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q015', (select id from chapters where code='sci-chem'), 201, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the smallest unit that makes up a larger piece of a substance or material called?', null, '["Atom", "Molecule", "Constituent particle", "Grain"]'::jsonb, 2, 'Constituent particle', 'Constituent particles are the building blocks of matter.  ▸ Textbook: A constituent particle is the basic unit that makes up a larger piece of a substance or material.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q016', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What happens to the interparticle forces when a liquid is heated to its boiling point?', null, '["They become stronger", "They remain unchanged", "They get weakened", "They disappear completely"]'::jsonb, 2, 'They get weakened', 'Heating makes particles move faster, weakening the forces.  ▸ Textbook: The movement of particles becomes so vigorous that they move apart from each other, resulting in a decrease in the interparticle forces of attraction.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q017', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the process called when a solid turns into a liquid?', null, '["Freezing", "Melting", "Condensation", "Sublimation"]'::jsonb, 1, 'Melting', 'Melting is when a solid becomes a liquid.  ▸ Textbook: The temperature at which this happens is the melting point of the solid.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q019', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the term for the temperature at which a liquid turns into a gas?', null, '["Freezing point", "Melting point", "Boiling point", "Sublimation point"]'::jsonb, 2, 'Boiling point', 'The boiling point is when a liquid becomes a gas.  ▸ Textbook: The temperature at which a liquid boils and turns into vapour at atmospheric pressure is called its boiling point.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q021', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the main reason gases can fill any container they are in?', null, '["They have strong interparticle attractions", "They have weak interparticle attractions", "They are heavier than liquids", "They are lighter than solids"]'::jsonb, 1, 'They have weak interparticle attractions', 'Weak attractions allow gas particles to move freely and fill space.  ▸ Textbook: The particles in gases move freely in all directions and the interparticle attractions are negligible.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q023', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which state of matter has particles that can only vibrate in place?', null, '["Solid", "Liquid", "Gas", "Plasma"]'::jsonb, 0, 'Solid', 'Solid particles are tightly packed and can only vibrate.  ▸ Textbook: The particles can only move to and fro about their positions (vibrate or oscillate) but cannot move past each other.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q024', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the process called when a liquid turns into a gas at its boiling point?', null, '["Evaporation", "Condensation", "Boiling", "Sublimation"]'::jsonb, 2, 'Boiling', 'Boiling is when a liquid rapidly turns into gas at its boiling point.  ▸ Textbook: At the boiling point, the formation of vapour is very fast and occurs not only at the surface but also within the liquid.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-chem-q025', (select id from chapters where code='sci-chem'), 202, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the main characteristic of gases that distinguishes them from solids and liquids?', null, '["They have a fixed shape", "They have a fixed volume", "They have no fixed shape or volume", "They have strong interparticle attractions"]'::jsonb, 2, 'They have no fixed shape or volume', 'Gases spread out to fill any container, unlike solids and liquids.  ▸ Textbook: Gases do not have a fixed shape or volume and tend to occupy the entire available space.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q001', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the primary function of the cell membrane?', null, '["To enclose the cytoplasm and nucleus", "To provide rigidity and strength", "To store important substances", "To perform photosynthesis"]'::jsonb, 0, 'To enclose the cytoplasm and nucleus', 'The cell membrane''s main role is to enclose and protect the cell''s contents.  ▸ Textbook: The cell membrane encloses the cytoplasm and nucleus.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q002', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which organelle is responsible for photosynthesis in plant cells?', null, '["Nucleus", "Vacuole", "Chloroplast", "Cell wall"]'::jsonb, 2, 'Chloroplast', 'Chloroplasts contain chlorophyll, which is essential for photosynthesis.  ▸ Textbook: Some plastids, like chloroplasts, contain chlorophyll, which makes them green and helps in photosynthesis.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q003', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the role of the vacuole in plant cells?', null, '["To regulate cell activities", "To store important substances and maintain cell shape", "To perform photosynthesis", "To separate one cell from another"]'::jsonb, 1, 'To store important substances and maintain cell shape', 'Vacuoles store substances and help maintain the cell''s shape.  ▸ Textbook: This helps the plant cell store important substances, get rid of waste, and maintain the shape of the cell.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q004', (select id from chapters where code='sci-bio'), 205, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'How do animal cells differ from plant cells in terms of vacuoles?', null, '["Animal cells have large vacuoles, while plant cells do not", "Animal cells have small vacuoles, if present, while plant cells have large vacuoles", "Animal cells have no vacuoles, while plant cells have small vacuoles", "Animal cells and plant cells have vacuoles of the same size"]'::jsonb, 1, 'Animal cells have small vacuoles, if present, while plant cells have large vacuoles', 'Animal cells typically have smaller vacuoles compared to plant cells.  ▸ Textbook: In animal cells, vacuoles are usually not present, if present, they are usually small.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q005', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What structure provides rigidity and strength to plant cells?', null, '["Cell membrane", "Nucleus", "Cell wall", "Cytoplasm"]'::jsonb, 2, 'Cell wall', 'The cell wall is a rigid structure that supports plant cells.  ▸ Textbook: The cell wall in the plant cell provides rigidity and strength to plants.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q006', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which part of the cell is responsible for regulating all activities within the cell?', null, '["Cytoplasm", "Cell wall", "Nucleus", "Vacuole"]'::jsonb, 2, 'Nucleus', 'The nucleus controls the cell''s activities and growth.  ▸ Textbook: The nucleus regulates all activities that occur within the cell.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q007', (select id from chapters where code='sci-bio'), 203, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the main difference in shape between muscle cells and nerve cells?', null, '["Muscle cells are round, nerve cells are spindle-shaped", "Muscle cells are spindle-shaped, nerve cells are long with branches", "Muscle cells are long with branches, nerve cells are round", "Muscle cells and nerve cells have the same shape"]'::jsonb, 1, 'Muscle cells are spindle-shaped, nerve cells are long with branches', 'Muscle cells are spindle-shaped, while nerve cells are long and branched.  ▸ Textbook: A muscle cell (Fig. 2.6a) is shaped like a spindle, while a nerve cell (Fig. 2.6b) is very long and has branches.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q008', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the function of cytoplasm in a cell?', null, '["To perform photosynthesis", "To regulate cell activities", "To contain other components of the cell and compounds", "To provide rigidity and strength"]'::jsonb, 2, 'To contain other components of the cell and compounds', 'Cytoplasm holds the cell''s components and is where many life processes occur.  ▸ Textbook: Cytoplasm contains other components of the cell and compounds, such as carbohydrates, proteins, fats, and mineral salts.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q009', (select id from chapters where code='sci-bio'), 203, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Which of the following is NOT a basic part of a cell?', null, '["Cell membrane", "Nucleus", "Cytoplasm", "Chloroplast"]'::jsonb, 3, 'Chloroplast', 'Chloroplasts are not found in all cells, only in plant cells for photosynthesis.  ▸ Textbook: These three — cell membrane, cytoplasm, and nucleus — are the basic parts of a cell.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q010', (select id from chapters where code='sci-bio'), 205, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Why do plant cells have a cell wall, but animal cells do not?', null, '["To allow photosynthesis", "To provide rigidity and strength", "To store substances", "To regulate cell activities"]'::jsonb, 1, 'To provide rigidity and strength', 'The cell wall gives plant cells their firm structure, which is not needed in animal cells.  ▸ Textbook: The cell wall in the plant cell provides rigidity and strength to plants.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q011', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the primary function of plastids in plant cells?', null, '["To store waste", "To regulate cell activities", "To perform photosynthesis and store substances", "To separate cells"]'::jsonb, 2, 'To perform photosynthesis and store substances', 'Plastids are involved in photosynthesis and storage in plant cells.  ▸ Textbook: Some plastids, like chloroplasts, contain chlorophyll, which makes them green and helps in photosynthesis. In non-green parts, they help in the storag');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q012', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following structures is porous and allows the entry and exit of materials?', null, '["Cell wall", "Nucleus", "Cell membrane", "Vacuole"]'::jsonb, 2, 'Cell membrane', 'The cell membrane controls what enters and leaves the cell.  ▸ Textbook: It is porous and allows the entry of materials essential for life processes and the exit of waste material.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q014', (select id from chapters where code='sci-bio'), 205, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Which organelle is typically larger in plant cells compared to animal cells?', null, '["Nucleus", "Vacuole", "Cytoplasm", "Cell membrane"]'::jsonb, 1, 'Vacuole', 'Plant cells have larger vacuoles to store substances and maintain shape.  ▸ Textbook: In animal cells, vacuoles are usually not present, if present, they are usually small.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q015', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the role of chlorophyll in chloroplasts?', null, '["To store waste", "To regulate cell activities", "To perform photosynthesis", "To provide rigidity"]'::jsonb, 2, 'To perform photosynthesis', 'Chlorophyll is essential for capturing light energy for photosynthesis.  ▸ Textbook: Some plastids, like chloroplasts, contain chlorophyll, which makes them green and helps in photosynthesis.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q016', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which part of the cell is responsible for separating one cell from another?', null, '["Nucleus", "Cytoplasm", "Cell wall", "Cell membrane"]'::jsonb, 3, 'Cell membrane', 'The cell membrane acts as a boundary between cells.  ▸ Textbook: The cell membrane separates one cell from another.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q017', (select id from chapters where code='sci-bio'), 203, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'How do the shapes of muscle and nerve cells relate to their functions?', null, '["Muscle cells are long for contraction, nerve cells are round for signal transmission", "Muscle cells are spindle-shaped for contraction, nerve cells are long for signal transmission", "Muscle cells are round for contraction, nerve cells are spindle-shaped for signal transmission", "Muscle cells and nerve cells have the same shape for different functions"]'::jsonb, 1, 'Muscle cells are spindle-shaped for contraction, nerve cells are long for signal transmission', 'The shape of each cell type is suited to its specific function.  ▸ Textbook: A muscle cell (Fig. 2.6a) is shaped like a spindle, while a nerve cell (Fig. 2.6b) is very long and has branches.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q018', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the main function of the cell wall in plant cells?', null, '["To regulate cell activities", "To perform photosynthesis", "To provide rigidity and strength", "To store substances"]'::jsonb, 2, 'To provide rigidity and strength', 'The cell wall supports and protects plant cells.  ▸ Textbook: The cell wall in the plant cell provides rigidity and strength to plants.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q019', (select id from chapters where code='sci-bio'), 205, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Which structure is found in plant cells but not typically in animal cells?', null, '["Nucleus", "Cell membrane", "Chloroplast", "Cytoplasm"]'::jsonb, 2, 'Chloroplast', 'Chloroplasts are unique to plant cells for photosynthesis.  ▸ Textbook: Some plastids, like chloroplasts, contain chlorophyll, which makes them green and helps in photosynthesis.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q020', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the primary role of the nucleus in a cell?', null, '["To perform photosynthesis", "To store substances", "To regulate all activities within the cell", "To provide rigidity and strength"]'::jsonb, 2, 'To regulate all activities within the cell', 'The nucleus is the control center of the cell.  ▸ Textbook: The nucleus regulates all activities that occur within the cell.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q021', (select id from chapters where code='sci-bio'), 205, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'How do plant cells maintain their shape?', null, '["Through the cell membrane", "Through the nucleus", "Through the vacuole and cell wall", "Through the cytoplasm"]'::jsonb, 2, 'Through the vacuole and cell wall', 'The vacuole and cell wall help maintain the plant cell''s shape.  ▸ Textbook: This helps the plant cell store important substances, get rid of waste, and maintain the shape of the cell.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q022', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the primary function of the cytoplasm?', null, '["To perform photosynthesis", "To regulate cell activities", "To contain other components of the cell and compounds", "To provide rigidity and strength"]'::jsonb, 2, 'To contain other components of the cell and compounds', 'Cytoplasm is where most cellular processes occur.  ▸ Textbook: Cytoplasm contains other components of the cell and compounds, such as carbohydrates, proteins, fats, and mineral salts.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q023', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which organelle is responsible for storing substances in plant cells?', null, '["Nucleus", "Vacuole", "Chloroplast", "Cell membrane"]'::jsonb, 1, 'Vacuole', 'Vacuoles store substances and help maintain cell shape.  ▸ Textbook: This helps the plant cell store important substances, get rid of waste, and maintain the shape of the cell.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q024', (select id from chapters where code='sci-bio'), 205, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the difference in vacuole size between plant and animal cells?', null, '["Plant cells have smaller vacuoles than animal cells", "Plant cells have larger vacuoles than animal cells", "Both have the same size vacuoles", "Animal cells have no vacuoles"]'::jsonb, 1, 'Plant cells have larger vacuoles than animal cells', 'Plant cells have larger vacuoles to store more substances.  ▸ Textbook: In animal cells, vacuoles are usually not present, if present, they are usually small.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q025', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which structure is responsible for photosynthesis in plant cells?', null, '["Nucleus", "Vacuole", "Chloroplast", "Cell wall"]'::jsonb, 2, 'Chloroplast', 'Chloroplasts are essential for photosynthesis in plant cells.  ▸ Textbook: Some plastids, like chloroplasts, contain chlorophyll, which makes them green and helps in photosynthesis.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-bio-q026', (select id from chapters where code='sci-bio'), 204, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the role of the cell membrane in a cell?', null, '["To perform photosynthesis", "To regulate cell activities", "To enclose the cytoplasm and nucleus", "To provide rigidity and strength"]'::jsonb, 2, 'To enclose the cytoplasm and nucleus', 'The cell membrane protects and contains the cell''s contents.  ▸ Textbook: The cell membrane encloses the cytoplasm and nucleus.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q001', (select id from chapters where code='sci-phys'), 207, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is a concave mirror?', null, '["A mirror with a reflecting surface that curves inwards", "A mirror with a reflecting surface that curves outwards", "A flat mirror", "A mirror with no curvature"]'::jsonb, 0, 'A mirror with a reflecting surface that curves inwards', 'A concave mirror curves inward, like the inside of a spoon.  ▸ Textbook: A spherical mirror, which has a reflecting surface that curves inwards, is called a concave mirror.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q002', (select id from chapters where code='sci-phys'), 207, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which type of mirror is used as a side-view mirror in vehicles?', null, '["Concave mirror", "Convex mirror", "Plane mirror", "None of the above"]'::jsonb, 1, 'Convex mirror', 'Convex mirrors provide a wider field of view, which is useful for side-view mirrors.  ▸ Textbook: Look at the side-view mirrors on vehicles. These mirrors are convex.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q003', (select id from chapters where code='sci-phys'), 209, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What happens to the image when an object is moved away from a concave mirror?', null, '["The image becomes erect and enlarged", "The image becomes inverted and enlarged", "The image becomes inverted and smaller", "The image remains the same"]'::jsonb, 2, 'The image becomes inverted and smaller', 'As the object moves away, the image inverts and reduces in size.  ▸ Textbook: However, when the object is moved farther away, the image becomes inverted. Initially, the image is enlarged in size and then keeps getting smaller.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q004', (select id from chapters where code='sci-phys'), 206, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the angle of reflection when a light ray falls along the normal to a mirror?', null, '["0°", "45°", "90°", "180°"]'::jsonb, 0, '0°', 'When light falls along the normal, it reflects back on the same path, making the angle of reflection 0°.  ▸ Textbook: Finally, let the incident beam fall on the mirror along the normal and observe the direction of the reflected beam. What would be the angle of inciden');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q005', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following is true for a convex lens?', null, '["It diverges light beams", "It converges light beams", "It reflects light beams", "It does not affect light beams"]'::jsonb, 1, 'It converges light beams', 'A convex lens focuses light beams to a point, hence it converges them.  ▸ Textbook: The convex lens converges the light falling on it while the concave lens diverges the light.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q006', (select id from chapters where code='sci-phys'), 209, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What type of image does a convex mirror always form?', null, '["Erect and enlarged", "Erect and diminished", "Inverted and enlarged", "Inverted and diminished"]'::jsonb, 1, 'Erect and diminished', 'Convex mirrors always produce smaller, upright images.  ▸ Textbook: In case of a convex mirror, the image is always erect and smaller than the object, that is diminished.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q007', (select id from chapters where code='sci-phys'), 207, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Why are convex mirrors used in road safety mirrors?', null, '["They provide a larger view area", "They provide a smaller view area", "They invert the image", "They enlarge the image"]'::jsonb, 0, 'They provide a larger view area', 'Convex mirrors give a wider field of view, which helps in seeing more of the road.  ▸ Textbook: Further, such convex mirrors are installed at road intersections or sharp bends to provide drivers from both sides the visibility of the other side an');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q008', (select id from chapters where code='sci-phys'), 206, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What happens to parallel light beams when they fall on a concave mirror?', null, '["They remain parallel", "They diverge", "They converge", "They reflect back"]'::jsonb, 2, 'They converge', 'Concave mirrors focus parallel beams to a point, causing them to converge.  ▸ Textbook: However, when multiple beams of light fall upon a concave mirror, the multiple reflected beams get closer, that is, they converge.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q009', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the main function of a convex lens in optical devices?', null, '["To diverge light", "To converge light", "To reflect light", "To absorb light"]'::jsonb, 1, 'To converge light', 'Convex lenses focus light to a point, which is useful in devices like cameras and glasses.  ▸ Textbook: A convex lens is also called a converging lens while a concave lens is called a diverging lens.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q010', (select id from chapters where code='sci-phys'), 209, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which statement is true about the image formed by a concave lens?', null, '["It is always erect and enlarged", "It is always erect and diminished", "It is always inverted and enlarged", "It is always inverted and diminished"]'::jsonb, 1, 'It is always erect and diminished', 'Concave lenses always produce smaller, upright images.  ▸ Textbook: An object placed behind a concave lens and seen through the lens, always appears erect and diminished in size.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q011', (select id from chapters where code='sci-phys'), 209, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What happens to the image when an object is placed close to a concave mirror?', null, '["The image is erect and enlarged", "The image is inverted and enlarged", "The image is erect and diminished", "The image is inverted and diminished"]'::jsonb, 0, 'The image is erect and enlarged', 'Close objects in concave mirrors appear larger and upright.  ▸ Textbook: In the concave mirror, when the object is placed close to the mirror, the image is erect but larger than the object in size, that is, enlarged.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q013', (select id from chapters where code='sci-phys'), 209, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following is a characteristic of a plane mirror?', null, '["It forms an inverted image", "It forms an erect image of the same size", "It forms a diminished image", "It forms an enlarged image"]'::jsonb, 1, 'It forms an erect image of the same size', 'Plane mirrors reflect images that are the same size and orientation as the object.  ▸ Textbook: A plane mirror always forms an erect image of the same size as the object.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q014', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the effect of a convex lens on parallel light beams?', null, '["It diverges them", "It converges them", "It reflects them", "It absorbs them"]'::jsonb, 1, 'It converges them', 'Convex lenses focus parallel beams to a point, converging them.  ▸ Textbook: The convex lens converges the light falling on it while the concave lens diverges the light.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q015', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which type of lens is used in a magnifying glass?', null, '["Concave lens", "Convex lens", "Plane lens", "Bifocal lens"]'::jsonb, 1, 'Convex lens', 'Magnifying glasses use convex lenses to enlarge images.  ▸ Textbook: Have you seen a magnifying glass as shown in Fig. 10.14? It is also a lens that helps in reading small print by making the letters appear bigger.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q017', (select id from chapters where code='sci-phys'), 206, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the law of reflection regarding the angle of incidence and reflection?', null, '["The angle of incidence is always greater than the angle of reflection", "The angle of incidence is always less than the angle of reflection", "The angle of incidence is equal to the angle of reflection", "The angle of incidence is unrelated to the angle of reflection"]'::jsonb, 2, 'The angle of incidence is equal to the angle of reflection', 'The law states that the angle at which light hits a surface equals the angle at which it reflects.  ▸ Textbook: If done carefully, the experiment shows that the angle of incidence (i) is equal to the angle of reflection (r). This is a law of reflection.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q018', (select id from chapters where code='sci-phys'), 207, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Which type of mirror is used by dentists to provide an enlarged view of teeth?', null, '["Plane mirror", "Concave mirror", "Convex mirror", "None of the above"]'::jsonb, 1, 'Concave mirror', 'Concave mirrors enlarge images, useful for detailed views like in dentistry.  ▸ Textbook: It is a concave mirror which provides an enlarged view of teeth when held close to the teeth inside the mouth.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q020', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'What is the shape of a convex lens?', null, '["Thicker at the edges than the middle", "Thicker at the middle than the edges", "Flat on both sides", "Curved inward on both sides"]'::jsonb, 1, 'Thicker at the middle than the edges', 'Convex lenses bulge outwards, being thicker in the center.  ▸ Textbook: A lens which is thicker at the middle as compared to the edges is called a convex lens.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q021', (select id from chapters where code='sci-phys'), 207, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Which type of mirror is used in the headlights of cars?', null, '["Plane mirror", "Concave mirror", "Convex mirror", "None of the above"]'::jsonb, 1, 'Concave mirror', 'Concave mirrors focus light into a beam, useful for headlights.  ▸ Textbook: The reflectors of torches, headlights of cars and scooters are concave in shape.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q023', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which of the following is a characteristic of a concave lens?', null, '["It converges light beams", "It diverges light beams", "It reflects light beams", "It absorbs light beams"]'::jsonb, 1, 'It diverges light beams', 'Concave lenses spread out light beams, causing them to diverge.  ▸ Textbook: The convex lens converges the light falling on it while the concave lens diverges the light.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q024', (select id from chapters where code='sci-phys'), 206, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the effect of a concave mirror on parallel light beams?', null, '["They remain parallel", "They diverge", "They converge", "They reflect back"]'::jsonb, 2, 'They converge', 'Concave mirrors focus parallel beams to a point, causing them to converge.  ▸ Textbook: However, when multiple beams of light fall upon a concave mirror, the multiple reflected beams get closer, that is, they converge.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q025', (select id from chapters where code='sci-phys'), 209, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What type of image does a concave mirror form when the object is far away?', null, '["Erect and enlarged", "Inverted and enlarged", "Inverted and diminished", "Erect and diminished"]'::jsonb, 2, 'Inverted and diminished', 'Far objects in concave mirrors appear smaller and inverted.  ▸ Textbook: However, when the object is moved farther away, the image becomes inverted. Initially, the image is enlarged in size and then keeps getting smaller.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q026', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 1, 'easy', 60, 'mcq', 'Which type of lens is thicker at the edges than at the middle?', null, '["Convex lens", "Concave lens", "Plane lens", "Bifocal lens"]'::jsonb, 1, 'Concave lens', 'Concave lenses are thinner in the center, causing them to spread light.  ▸ Textbook: A lens which is thicker at the edges as compared to the middle is called a concave lens.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q031', (select id from chapters where code='sci-phys'), 207, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the purpose of using a concave mirror in a solar cooker?', null, '["To diverge sunlight", "To converge sunlight", "To reflect sunlight", "To absorb sunlight"]'::jsonb, 1, 'To converge sunlight', 'Concave mirrors focus sunlight to a point, increasing heat for cooking.  ▸ Textbook: Devices which concentrate sunlight into a small area, using mirrors and lenses, are called solar concentrators.');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q033', (select id from chapters where code='sci-phys'), 208, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'What is the effect of a convex lens on sunlight?', null, '["It diverges sunlight", "It converges sunlight", "It reflects sunlight", "It absorbs sunlight"]'::jsonb, 1, 'It converges sunlight', 'Convex lenses focus sunlight to a point, concentrating heat.  ▸ Textbook: Repeat Activity 10.7 by putting a convex lens in the path of sunrays in place of a concave mirror. Could you burn the paper?');
insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('sci-phys-q034', (select id from chapters where code='sci-phys'), 207, 'NCERT Curiosity Grade 8', 2, 'medium', 120, 'mcq', 'Which type of mirror is used in telescopes to gather light?', null, '["Plane mirror", "Concave mirror", "Convex mirror", "None of the above"]'::jsonb, 1, 'Concave mirror', 'Concave mirrors focus light, making them ideal for telescopes.  ▸ Textbook: Most modern telescopes are reflecting telescope that use curved mirrors, with the main mirror being a large concave mirror.');
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='sci-chem'), 1, 'Particles of matter, and the three states', '*', 'Rarely asked directly (2/59 papers), but it underpins everything else.', '[{"kind": "p", "text": "All matter is made of very small pieces called CONSTITUENT PARTICLES. Break chalk, grind it, dissolve sugar — you never get a new substance, only smaller and smaller pieces of the same one."}, {"kind": "key", "text": "What state a substance is in is decided by the strength of the ATTRACTION between its particles."}, {"kind": "tbl", "head": ["State", "Particles", "Shape", "Volume"], "rows": [["Solid", "tightly packed, fixed positions, can only vibrate", "definite", "definite"], ["Liquid", "loosely packed, can slide past each other", "takes the container''s shape", "definite"], ["Gas", "far apart, free to move in all directions", "fills the whole container", "no fixed volume"]]}, {"kind": "key", "text": "Heating WEAKENS the attraction between particles. Solid → (melting point) → liquid → (boiling point) → gas."}, {"kind": "warn", "text": "Your test stops at book page 106. Interparticle SPACING (section 7.3) is NOT in scope."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='sci-bio'), 1, 'The cell and its organelles', '**', 'Cell structure came up in 29 of the 59 real Science papers.', '[{"kind": "p", "text": "Every living thing is built from cells. A cell has THREE basic parts: the cell membrane, the cytoplasm, and the nucleus. Plant cells add a few more."}, {"kind": "tbl", "head": ["Organelle", "What it does"], "rows": [["Cell membrane", "Encloses the cytoplasm and nucleus. Separates one cell from another. POROUS — lets useful things in and waste out."], ["Cytoplasm", "Fills the space between membrane and nucleus. Holds the other components. MOST life processes happen here."], ["Nucleus", "Regulates ALL activities of the cell, and its growth."], ["Cell wall (plants only)", "Gives rigidity and strength — which is why plant cells look firm and packed."], ["Chloroplast (a plastid)", "Contains chlorophyll → green → does photosynthesis. In non-green parts, plastids store substances."], ["Vacuole", "Stores substances, gets rid of waste, keeps the cell''s shape. LARGE in plant cells; small or absent in animal cells."]]}, {"kind": "key", "text": "Plant cell vs animal cell: a plant cell has a CELL WALL, CHLOROPLASTS and a LARGE VACUOLE. An animal cell has none of those (its vacuoles, if any, are small)."}, {"kind": "p", "text": "A cell''s SHAPE follows its job: a muscle cell is spindle-shaped so it can contract; a nerve cell is long with branches so it can carry signals a long way."}, {"kind": "warn", "text": "Careful — this textbook LABELS mitochondria in Fig 2.5 but never says what it does. If your test asks for its function, that came from class, not this book."}]'::jsonb);
insert into concept_sections (chapter_id, idx, title, tier, why, body) values ((select id from chapters where code='sci-phys'), 1, 'Light: mirrors, reflection and lenses', '***', 'Reflection and mirrors came up in 30 of the 59 real Science papers — the most-asked Science topic.', '[{"kind": "key", "text": "Law of reflection: the angle of incidence = the angle of reflection. Both are measured from the NORMAL (the line at 90° to the mirror), never from the mirror surface."}, {"kind": "p", "text": "So if a ray comes straight along the normal, the angle of incidence is 0° — and it reflects straight back."}, {"kind": "tbl", "head": ["", "Shape", "Effect on parallel rays", "Image"], "rows": [["Concave mirror", "curves INWARDS", "converges them", "far object → inverted & smaller; close object → erect & enlarged"], ["Convex mirror", "curves OUTWARDS", "diverges them", "ALWAYS erect and diminished; wider view"], ["Convex lens", "thicker in the MIDDLE", "converges them", "far object → inverted & smaller; close object → erect & enlarged"], ["Concave lens", "thicker at the EDGES", "diverges them", "ALWAYS erect and diminished"]]}, {"kind": "key", "text": "The pattern to hold on to: CONVEX MIRROR and CONCAVE LENS always give an erect, diminished image. CONCAVE MIRROR and CONVEX LENS depend on how far the object is."}, {"kind": "eg", "lines": ["Convex mirror → vehicle side-view mirrors, road safety mirrors (they show a wide view)", "Concave mirror → dentist''s mirror, car headlights, solar cooker (they converge light)", "Convex lens → magnifying glass"]}]'::jsonb);
